        Arrays.fill(key, (byte) 0);
        key = null;
    }
    if (iv != null) {
        Arrays.fill(iv, (byte) 0);
        iv = null;
    }
    if (ctx != 0) {
        SDFJceNative.sm4Free(ctx);
        ctx = 0;
    }
    if (sessionHandle != 0) {
        SDFJceNative.closeSession(sessionHandle);
